import re
from semantic_kernel import Kernel

def detect_token_leakage(kernel: Kernel, function_result: str) -> bool:
    patterns = [
        r'Bearer\s+[A-Za-z0-9\-_]+\.?[A-Za-z0-9\-_]*',
        r'(sk|ak|pk|Bearer)[A-Za-z0-9]{32,}',
        r'Basic\s+[A-Za-z0-9+/]+=*'
    ]
    for pattern in patterns:
        if re.search(pattern, function_result, re.IGNORECASE):
            return True
    return False

# Usage in kernel function
result = await kernel.invoke('MyPlugin', 'GetUserData')
if detect_token_leakage(kernel, str(result)):
    raise ValueError('Auth token detected in function output')

