from collections import deque

class AuthCascadeDetector:
    def __init__(self, window_size: int = 5):
        self.error_window = deque(maxlen=window_size)
        self.auth_errors = ['401', 'Unauthorized', 'Forbidden']

    def check_cascade(self, error_msg: str) -> bool:
        if any(auth_err in error_msg for auth_err in self.auth_errors):
            self.error_window.append('auth_error')
            return len(self.error_window) >= 3  # 3+ consecutive auth errors
        return False

# Integrate with error handler
detector = AuthCascadeDetector()
try:
    result = await kernel.invoke('ChainedPlugin')
except Exception as e:
    if detector.check_cascade(str(e)):
        print('Auth cascade detected - check token propagation')

import json
from semantic_kernel.planning import SequentialPlanner

def validate_plan_scopes(plan_json: str, allowed_scopes: list[str]) -> bool:
    plan = json.loads(plan_json)
    required_scopes = set()

    for step in plan.get('steps', []):
        function_name = step.get('function', '')
        # Map function names to required scopes
        scope_map = {
            'admin_user_update': ['admin:write'],
            'enterprise_search': ['enterprise:read'],
            'public_chat': []  # No scopes required
        }
        required_scopes.update(scope_map.get(function_name, ['unknown']))

    return required_scopes.issubset(set(allowed_scopes))

planner = SequentialPlanner(kernel)
plan = await planner.create_plan('Update enterprise user data')
if not validate_plan_scopes(str(plan), ['user:read']):
    raise PermissionError('Planner generated unauthorized plan')

