import re
from semantic_kernel.memory import SemanticTextMemory

class SecureMemory(SemanticTextMemory):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.token_patterns = [
            r'Bearer\s+[A-Za-z0-9\-_]+',
            r'(sk-[A-Za-z0-9]{48})',
            r'Basic\s+[A-Za-z0-9+/]+=+'
        ]

    def sanitize_content(self, content: str) -> str:
        for pattern in self.token_patterns:
            content = re.sub(pattern, '[REDACTED]', content, flags=re.IGNORECASE)
        return content

    async def save_information_async(self, collection: str, text: str, **kwargs):
        sanitized_text = self.sanitize_content(text)
        return await super().save_information_async(collection, sanitized_text, **kwargs)

# Usage
